const data = $getWorkflowStaticData('global');
data.users_pages_loaded = 0;
data.users_rows_loaded = 0;
return [{ json: { url: 'https://kipuhealth.zendesk.com/api/v2/users.json?role[]=agent&page=1&per_page=100' } }];

