const batch = $('Code - Prepare Batch IDs').first().json || {};
const prepSync = $('Code - Prepare Run Sync Search').first().json || {};

const tickets = Array.isArray($('HTTP - Fetch Ticket Batch').first().json.tickets)
  ? $('HTTP - Fetch Ticket Batch').first().json.tickets
  : [];

const metricItems = $('HTTP - Fetch Ticket Metrics').all();

const metricsByTicketId = {};
for (const item of metricItems) {
  const metric = item.json?.ticket_metric || {};
  if (metric.ticket_id != null) {
    metricsByTicketId[String(metric.ticket_id)] = metric;
  }
}

const formName = batch.form_name ?? null;
const ARTICLE_LINKED_FIELD_IDS = [18158428639387, 25171038337691];

function getCustomFieldValue(ticket, fieldIds) {
  const fields = Array.isArray(ticket.custom_fields) ? ticket.custom_fields : [];
  for (const fieldId of fieldIds) {
    const match = fields.find(f => Number(f.id) === Number(fieldId));
    if (match && match.value !== undefined && match.value !== null && match.value !== '') {
      return match.value;
    }
  }
  return null;
}

function hasAnyTag(ticket, tagList) {
  const tags = Array.isArray(ticket.tags) ? ticket.tags : [];
  return tagList.some(tag => tags.includes(tag));
}

function normalizeBoolean(value, trueValues = [], falseValues = []) {
  if (value === true) return true;
  if (value === false) return false;
  if (value == null) return null;
  const v = String(value).toLowerCase().trim();
  if (['yes', 'true', '1'].includes(v)) return true;
  if (['no', 'false', '0'].includes(v)) return false;
  if (trueValues.map(x => String(x).toLowerCase()).includes(v)) return true;
  if (falseValues.map(x => String(x).toLowerCase()).includes(v)) return false;
  return null;
}

function getSlaBreachedFlag(ticket, metric) {
  const policyMetrics = Array.isArray(ticket.slas?.policy_metrics)
    ? ticket.slas.policy_metrics : [];
  if (!policyMetrics.length) return null;
  const solvedAt = metric?.solved_at ? new Date(metric.solved_at) : null;
  return policyMetrics.some(m => {
    if (!m.breach_at) return false;
    if (solvedAt) return new Date(m.breach_at) < solvedAt;
    return m.stage === 'breached';
  });
}

const rows = tickets.map(ticket => {
  const metric = metricsByTicketId[String(ticket.id)] || {};
  const resolution = metric.full_resolution_time_in_minutes?.business ?? null;

  const articleLinkedRaw = getCustomFieldValue(ticket, ARTICLE_LINKED_FIELD_IDS);
  let articleLinkedFlag = normalizeBoolean(
    articleLinkedRaw,
    ['kcs_linked_yes', 'kcslinked_yes'],
    ['kcs_linked_no', 'kcslinked_no']
  );
  if (articleLinkedFlag == null) {
    if (hasAnyTag(ticket, ['kcs_linked_yes', 'kcslinked_yes'])) articleLinkedFlag = true;
    else if (hasAnyTag(ticket, ['kcs_linked_no', 'kcslinked_no'])) articleLinkedFlag = false;
  }

  return {
    ticket_id: ticket.id ?? null,
    ticket_created_at: ticket.created_at ?? null,
    ticket_updated_at: ticket.updated_at ?? null,
    ticket_solved_at: metric.solved_at ?? ticket.solved_at ?? null,
    status: ticket.status ?? null,
    channel: ticket.via?.channel ?? null,
    form_id: ticket.ticket_form_id ?? null,
    form_name: formName,
    assignee_id: ticket.assignee_id ?? null,
    group_id: ticket.group_id ?? null,
    csat_score: ticket.satisfaction_rating?.score ?? null,
    first_reply_time_business_minutes: metric.reply_time_in_minutes?.business ?? null,
    next_reply_time_business_minutes: null,
    pausable_update_time_business_minutes: metric.on_hold_time_in_minutes?.business ?? null,
    requester_wait_time_business_minutes: metric.requester_wait_time_in_minutes?.business ?? null,
    full_resolution_time_business_minutes: resolution,
    one_business_day_solve_flag: resolution != null ? resolution <= 480 : null,
    sla_breached_flag: getSlaBreachedFlag(ticket, metric),
    article_linked_flag: articleLinkedFlag,
    missed_call_flag: null,
    ticket_count: 1
  };
}).filter(row => row.ticket_id != null);

return [{
  json: {
    run_id: batch.run_id || null,
    current_batch: Number(prepSync.chunk_num || 0),
    total_batches: Number(prepSync.total_chunks || 0),
    page_num: Number(batch.current_batch || 0),
    total_pages: Number(batch.total_batches || 0),
    expected_count: Number(batch.expected_count || rows.length),
    ticket_rows_json: JSON.stringify(rows),
    ticket_count: rows.length,
    input_rows: rows.length,
    batch_count: rows.length,
    total_count_estimate: Number(prepSync.total_count_estimate || 0),
    next_page_url: batch.next_page_url || null,
    end_of_stream: batch.end_of_stream === true
  }
}];

const results = Array.isArray($json.results) ? $json.results : [];

return [{
