const prepData = $('Code - Prep Count Query').first().json;
const totalCount = Number($json.count || 0);

const formId = prepData.form_id;
const formName = prepData.form_name || null;
const dateFrom = prepData.date_from;
const dateTo = prepData.date_to;

const rangeStart = new Date(dateFrom + 'T00:00:00Z');
const rangeEnd = new Date(dateTo + 'T00:00:00Z');
const fullRangeDays = Math.ceil((rangeEnd - rangeStart) / (1000 * 60 * 60 * 24));

// Target 750 tickets/chunk — leaves buffer below 1000 cap
// Count check node will catch any chunk that still exceeds limit
const avgPerDay = totalCount / fullRangeDays;
const CHUNK_DAYS = Math.max(1, Math.floor(750 / avgPerDay));

const runId = `ticket-sync-${formId}-${dateFrom.replace(/-/g, '')}-${Date.now()}`;

const chunks = [];
let cursor = new Date(rangeStart);

while (cursor < rangeEnd) {
  const chunkFrom = cursor.toISOString().slice(0, 10);
  const nextCursor = new Date(cursor);
  nextCursor.setUTCDate(nextCursor.getUTCDate() + CHUNK_DAYS);
  if (nextCursor > rangeEnd) nextCursor.setTime(rangeEnd.getTime());
  const chunkTo = nextCursor.toISOString().slice(0, 10);

  chunks.push({
    run_id: runId,
    form_id: formId,
    form_name: formName,
    date_from: chunkFrom,
    date_to: chunkTo,
    total_count_estimate: totalCount,
    chunk_days_used: CHUNK_DAYS,
    avg_per_day: Math.round(avgPerDay)
  });

  cursor = nextCursor;
}

const totalChunks = chunks.length;
return chunks.map((c, i) => ({
  json: { ...c, chunk_num: i + 1, total_chunks: totalChunks }
}));

